{
  "sentences": [
    {
      "text": "今天天氣太熱了，我心情不好。",
      "pinyin": "Jīntiān tiānqì tài rè le, wǒ xīnqíng bù hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 tai4 re4 le0, wo3 xin1qing2 bu4 hao3.",
      "translation_en": "The weather is too hot today, I'm in a bad mood.",
      "translation_ko": "오늘 날씨가 너무 더워서 기분이 안 좋아요."
    },
    {
      "text": "昨天颱風太大，我太緊張了。",
      "pinyin": "Zuótiān táifēng tài dà le, wǒ tài jǐnzhāng le.",
      "pinyin_numeric": "zuo2tian1 tai2feng1 tai4 da4 le0, wo3 tai4 jin3zhang1 le0.",
      "translation_en": "The typhoon yesterday was too big, I was too nervous.",
      "translation_ko": "어제 태풍이 너무 커서 너무 긴장했어요."
    },
    {
      "text": "今天晴天，可是風太大了，不太舒服。",
      "pinyin": "Jīntiān qíngtiān, kěshì fēng tài dà le, bù tài shūfu.",
      "pinyin_numeric": "jin1tian1 qing2tian1, ke3shi4 feng1 tai4 da4 le0, bu4 tai4 shu1fu0.",
      "translation_en": "Today is sunny, but the wind is too strong, not very comfortable.",
      "translation_ko": "오늘은 맑은데 바람이 너무 세서 별로 안 편해요."
    },
    {
      "text": "下雨天路太滑了，要小心走路。",
      "pinyin": "Xiàyǔ tiān lù tài huá le, yào xiǎoxīn zǒulù.",
      "pinyin_numeric": "xia4yu3 tian1 lu4 tai4 hua2 le0, yao4 xiao3xin1 zou3lu4.",
      "translation_en": "The road is too slippery on rainy days, you need to walk carefully.",
      "translation_ko": "비 오는 날 길이 너무 미끄러우니까 조심해서 걸어야 해요."
    },
    {
      "text": "今天溫度三十度，太悶熱了，我沒精神。",
      "pinyin": "Jīntiān wēndù sānshí dù, tài mēnrè le, wǒ méi jīngshén.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, tai4 men1re4 le0, wo3 mei2 jing1shen2.",
      "translation_en": "Today's temperature is 30 degrees, it's too muggy, I have no energy.",
      "translation_ko": "오늘 기온이 30도라서 너무 후덥지근해서 기운이 없어요."
    },
    {
      "text": "陰天心情太差了，我想喝咖啡放鬆。",
      "pinyin": "Yīntiān xīnqíng tài chà le, wǒ xiǎng hē kāfēi fàngsōng.",
      "pinyin_numeric": "yin1tian1 xin1qing2 tai4 cha4 le0, wo3 xiang3 he1 ka1fei1 fang4song1.",
      "translation_en": "My mood is too bad on cloudy days, I want to drink coffee to relax.",
      "translation_ko": "흐린 날에는 기분이 너무 안 좋아서 커피 마시면서 쉬고 싶어요."
    },
    {
      "text": "今天天氣太舒服了，我心情很開心。",
      "pinyin": "Jīntiān tiānqì tài shūfu le, wǒ xīnqíng hěn kāixīn.",
      "pinyin_numeric": "jin1tian1 tian1qi4 tai4 shu1fu0 le0, wo3 xin1qing2 hen3 kai1xin1.",
      "translation_en": "The weather is too comfortable today, I'm very happy.",
      "translation_ko": "오늘 날씨가 너무 쾌적해서 기분이 아주 좋아요."
    },
    {
      "text": "昨天太冷了，我穿外套，可是還是不舒服。",
      "pinyin": "Zuótiān tài lěng le, wǒ chuān wàitào, kěshì háishì bù shūfu.",
      "pinyin_numeric": "zuo2tian1 tai4 leng3 le0, wo3 chuan1 wai4tao4, ke3shi4 hai2shi4 bu4 shu1fu0.",
      "translation_en": "Yesterday was too cold, I wore a jacket, but still felt uncomfortable.",
      "translation_ko": "어제 너무 추워서 외투를 입었는데도 여전히 불편했어요."
    },
    {
      "text": "今天多雲，可是風太大，我壓力太大了。",
      "pinyin": "Jīntiān duōyún, kěshì fēng tài dà, wǒ yālì tài dà le.",
      "pinyin_numeric": "jin1tian1 duo1yun2, ke3shi4 feng1 tai4 da4, wo3 ya1li4 tai4 da4 le0.",
      "translation_en": "Today is cloudy, but the wind is too strong, my stress is too high.",
      "translation_ko": "오늘은 구름이 많지만 바람이 너무 세서 스트레스가 너무 커요."
    },
    {
      "text": "下雨天我太擔心了，因為路滑，要小心。",
      "pinyin": "Xiàyǔ tiān wǒ tài dānxīn le, yīnwèi lù huá, yào xiǎoxīn.",
      "pinyin_numeric": "xia4yu3 tian1 wo3 tai4 dan1xin1 le0, yin1wei4 lu4 hua2, yao4 xiao3xin1.",
      "translation_en": "I'm too worried on rainy days because the road is slippery, I need to be careful.",
      "translation_ko": "비 오는 날에는 너무 걱정돼요. 길이 미끄러우니까 조심해야 해요."
    }
  ]
}
